#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; N > j; ++j) {
        for (int i = 0; N > i; ++i) {
            if (0 == i || N-1 == i) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (0 == j || N-1 == j) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void compute_step_kernel(float* f, float* f_old, float* error_ptr, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int inner_size = (N-2) * (N-2);

    if (idx < inner_size) {
        int i = 1 + (idx % (N-2));
        int j = 1 + (idx / (N-2));

        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1]));
        float diff = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;
        error_ptr[idx] = diff * diff;
    }
}

__global__ void copy_kernel(float* f, float* f_old, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * N;

    if (idx < total) {
        int i = idx % N;
        int j = idx / N;

        if (1 <= j && N-2 >= j && 1 <= i && N-2 >= i) {
            f_old[IDX(i,j)] = f[IDX(i,j)];
        }
    }
}

int main() {
    auto tmp_3 = std::chrono::steady_clock::now();

    float* f_host = (float*)aligned_alloc(64, N * N * sizeof(float));
    float* f_old_host = (float*)aligned_alloc(64, N * N * sizeof(float));

    float* f_dev;
    float* f_old_dev;
    float* error_dev;

    cudaMalloc(&f_dev, N * N * sizeof(float));
    cudaMalloc(&f_old_dev, N * N * sizeof(float));
    cudaMalloc(&error_dev, (N-2) * (N-2) * sizeof(float));

    float elem_9 = std::numeric_limits<float>::max();
    const float x_6 = 1.e-5f;

    initialize_data(f_host);
    initialize_data(f_old_host);

    cudaMemcpy(f_dev, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(f_old_dev, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int x_4 = 10000;
    int tmp_10 = 0;

    int threads = 256;
    int blocks = ((N-2) * (N-2) + threads - 1) / threads;
    int copy_blocks = (N * N + threads - 1) / threads;

    auto item_1 = std::chrono::steady_clock::now();

    while (x_6 < elem_9 && x_4 > tmp_10) {
        elem_9 = 0.f;

        compute_step_kernel<<<blocks, threads>>>(f_dev, f_old_dev, error_dev, N);

        float* error_host = (float*)malloc((N-2) * (N-2) * sizeof(float));
        cudaMemcpy(error_host, error_dev, (N-2) * (N-2) * sizeof(float), cudaMemcpyDeviceToHost);

        for (int i = 0; i < (N-2) * (N-2); i++) {
            elem_9 += error_host[i];
        }
        free(error_host);

        copy_kernel<<<copy_blocks, threads>>>(f_dev, f_old_dev, N);

        elem_9 = sqrtf(elem_9 / (N * N));

        if (0 == tmp_10 % 1000) {
            std::cout << "Error after iteration " << tmp_10 << " = " << elem_9 << std::endl;
        }

        ++tmp_10;
    }

    auto end = std::chrono::steady_clock::now();
    auto var_2 = std::chrono::duration_cast<std::chrono::nanoseconds>(end - item_1).count();
    std::cout << "Average execution time per iteration: " << (var_2 * 1e-9f) / tmp_10 << " (s)\n";

    cudaMemcpy(f_host, f_dev, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    if (x_6 >= elem_9 && x_4 > tmp_10) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        return -1;
    }

